input.command:
$location='Crooked Corner NSW';
$todayDate='2026-03-07';
$tomorrowDate='2026-03-08';
$todayDesc='Slight rain showers';
$tomorrowDesc='Partly cloudy';
$todayMax=25.7; $todayMin=17.2; $todayP=1.7; $todayWind=10.0;
$tomMax=23.0; $tomMin=15.7; $tomP=0.0; $tomWind=30.6;
$desktop=[Environment]::GetFolderPath('Desktop');
$file=Join-Path $desktop 'weather_Crooked_Corner_NSW.txt';
$content=@(
"Weather for $location (timezone: Australia/Sydney)",
"Source: Open-Meteo (model forecast)",
"",
"Today ($todayDate): $todayDesc",
"  High: $todayMax °C  |  Low: $todayMin °C",
"  Precipitation: $todayP mm  |  Max wind: $todayWind km/h",
"",
"Tomorrow ($tomorrowDate): $tomorrowDesc",
"  High: $tomMax °C  |  Low: $tomMin °C",
"  Precipitation: $tomP mm  |  Max wind: $tomWind km/h"
) -join [Environment]::NewLine;
Set-Content -Path $file -Value $content -Encoding UTF8;
$file
